from flask import Flask, request, jsonify
import redis

app = Flask(__name__)

# Redis connection settings
redis_config = {
    'host': 'localhost',
    'port': 6379,
    'db': 0
}

# Create a Redis client instance
r = redis.Redis(**redis_config)

@app.route('/execute', methods=['POST'])
def execute_redis_command():
    try:
        # Get the command from the request arguments
        command = request.args.get('command')
        
        if not command:
            return jsonify({'error': 'Missing required parameter: command'}), 400
        
        # Validate and sanitize the input command
        allowed_commands = ['GET', 'SET', 'DEL', 'EXPIRE', 'TTL']
        if command.upper() not in allowed_commands:
            return jsonify({'error': f'Invalid Redis command: {command}'}), 403
        
        # Execute the Redis command using redis.execute_command()
        result = r.execute_command(command)
        
        return jsonify({'result': result}), 200
    
    except Exception as e:
        return jsonify({'error': str(e)}), 500

if __name__ == '__main__':
    app.run(debug=True)